'use server';

import { updateTag } from 'next/cache';

import { insertPost } from '@/lib/posts';

export async function createPost(formData: FormData): Promise<void> {
  const title = String(formData.get('title') ?? '').trim();
  const body = String(formData.get('body') ?? '').trim();

  if (!title || !body) {
    throw new Error('Title and body are required.');
  }

  insertPost(title, body);

  // updateTag expires the cache immediately. The next request waits for
  // fresh data instead of serving the stale posts list.
  updateTag('posts');
}
import { unstable_cache } from 'next/cache';

export type Post = {
  id: string;
  title: string;
  body: string;
  createdAt: string;
};

// Replace this store with the application's database in production.
let posts: Post[] = [];

async function readPosts(): Promise<Post[]> {
  return posts.map((post) => ({ ...post }));
}

export const getPosts = unstable_cache(readPosts, ['posts'], {
  tags: ['posts']
});

export function insertPost(title: string, body: string): Post {
  const post: Post = {
    id: crypto.randomUUID(),
    title,
    body,
    createdAt: new Date().toISOString()
  };

  posts = [post, ...posts];
  return post;
}
import { createPost } from './actions';
import { getPosts } from '@/lib/posts';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main>
      <h1>Posts</h1>
      <form action={createPost}>
        <p>
          <label htmlFor="title">Title</label>
          <input id="title" name="title" required />
        </p>
        <p>
          <label htmlFor="body">Body</label>
          <textarea id="body" name="body" required />
        </p>
        <button type="submit">Create post</button>
      </form>

      <section aria-labelledby="posts-heading">
        <h2 id="posts-heading">Recent posts</h2>
        {posts.length === 0 ? (
          <p>No posts yet.</p>
        ) : (
          <ul>
            {posts.map((post) => (
              <li key={post.id}>
                <h3>{post.title}</h3>
                <p>{post.body}</p>
              </li>
            ))}
          </ul>
        )}
      </section>
    </main>
  );
}
